content:
{
  "sentences": [
    {
      "text": "我常常在週末打籃球。",
      "pinyin": "Wǒ chángcháng zài zhōumò dǎ lánqiú.",
      "pinyin_numeric": "wo3 chang2chang2 zai4 zhou1mo4 da3 lan2qiu2.",
      "translation_en": "I often play basketball on weekends.",
      "translation_ko": "저는 주말에 자주 농구를 합니다."
    },
    {
      "text": "他常常看小說，很少看漫畫。",
      "pinyin": "Tā chángcháng kàn xiǎoshuō, hěn shǎo kàn mànhuà.",
      "pinyin_numeric": "ta1 chang2chang2 kan4 xiao3shuo1, hen3 shao3 kan4 man4hua4.",
      "translation_en": "He often reads novels, but rarely reads comics.",
      "translation_ko": "그는 자주 소설을 읽고, 만화는 거의 보지 않습니다."
    },
    {
      "text": "我們有時候一起騎腳踏車去公園。",
      "pinyin": "Wǒmen yǒu shíhou yīqǐ qí jiǎotàchē qù gōngyuán.",
      "pinyin_numeric": "wo3men5 you3 shi2hou5 yi1qi3 qi2 jiao3ta4che1 qu4 gong1yuan2.",
      "translation_en": "Sometimes we ride bicycles together to the park.",
      "translation_ko": "우리는 가끔 함께 자전거를 타고 공원에 갑니다."
    },
    {
      "text": "她常常聽廣播，也喜歡看演唱會。",
      "pinyin": "Tā chángcháng tīng guǎngbò, yě xǐhuān kàn yǎnchànghuì.",
      "pinyin_numeric": "ta1 chang2chang2 ting1 guang3bo4, ye3 xi3huan1 kan4 yan3chang4hui4.",
      "translation_en": "She often listens to the radio and also likes to watch concerts.",
      "translation_ko": "그녀는 자주 라디오를 듣고, 콘서트 보는 것도 좋아합니다."
    },
    {
      "text": "我弟弟常常打電動，從來不看書。",
      "pinyin": "Wǒ dìdi chángcháng dǎ diàndòng, cónglái bù kàn shū.",
      "pinyin_numeric": "wo3 di4di5 chang2chang2 da3 dian4dong4, cong2lai2 bu4 kan4 shu1.",
      "translation_en": "My younger brother often plays video games and never reads books.",
      "translation_ko": "제 남동생은 자주 게임을 하고, 책은 전혀 읽지 않습니다."
    },
    {
      "text": "放假的時候，我們常常去露營。",
      "pinyin": "Fàngjià de shíhou, wǒmen chángcháng qù lùyíng.",
      "pinyin_numeric": "fang4jia4 de5 shi2hou5, wo3men5 chang2chang2 qu4 lu4ying2.",
      "translation_en": "During holidays, we often go camping.",
      "translation_ko": "휴가 때 우리는 자주 캠핑을 갑니다."
    },
    {
      "text": "她常常彈鋼琴，有時候也彈吉他。",
      "pinyin": "Tā chángcháng tán gāngqín, yǒu shíhou yě tán jítā.",
      "pinyin_numeric": "ta1 chang2chang2 tan2 gang1qin2, you3 shi2hou5 ye3 tan2 ji2ta1.",
      "translation_en": "She often plays the piano, and sometimes also plays the guitar.",
      "translation_ko": "그녀는 자주 피아노를 치고, 가끔 기타도 칩니다."
    },
    {
      "text": "我爸爸常常釣魚，他覺得很好玩。",
      "pinyin": "Wǒ bàba chángcháng diào yú, tā juéde hěn hǎowán.",
      "pinyin_numeric": "wo3 ba4ba5 chang2chang2 diao4 yu2, ta1 jue2de5 hen3 hao3wan2.",
      "translation_en": "My father often goes fishing; he thinks it's a lot of fun.",
      "translation_ko": "아버지는 자주 낚시를 가십니다. 아버지는 그것이 아주 재미있다고 생각하십니다."
    },
    {
      "text": "我朋友常常爬山，他喜歡運動。",
      "pinyin": "Wǒ péngyou chángcháng pá shān, tā xǐhuān yùndòng.",
      "pinyin_numeric": "wo3 peng2you5 chang2chang2 pa2 shan1, ta1 xi3huan1 yun4dong4.",
      "translation_en": "My friend often goes hiking; he likes sports.",
      "translation_ko": "제 친구는 자주 등산을 합니다. 그는 운동을 좋아합니다."
    },
    {
      "text": "你常常看球賽嗎？要不要一起去？",
      "pinyin": "Nǐ chángcháng kàn qiúsài ma? Yào bù yào yīqǐ qù?",
      "pinyin_numeric": "ni3 chang2chang2 kan4 qiu2sai4 ma0? yao4 bu4 yao4 yi1qi3 qu4?",
      "translation_en": "Do you often watch ball games? Want to go together?",
      "translation_ko": "당신은 자주 경기를 보나요? 같이 갈래요?"
    }
  ]
}
